import React, { useState } from "react";

const Gallery = () => {
  const [lightbox, setLightbox] = useState(null);

  const galleryItems = [
    {
      src: "https://images.unsplash.com/photo-1602002418082-a4443e081dd1?w=800&q=80&auto=format",
      label: "Overwater Bungalow",
      span: "wide",
    },
    {
      src: "https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=600&q=80&auto=format",
      label: "Deluxe Room",
    },
    {
      src: "https://images.unsplash.com/photo-1571003123894-1f0594d2b5d9?w=600&q=80&auto=format",
      label: "Infinity Pool",
    },
    {
      src: "https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=600&q=80&auto=format",
      label: "Dining Area",
    },
    {
      src: "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80&auto=format",
      label: "Beachfront View",
      span: "wide",
    },
    {
      src: "https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=600&q=80&auto=format",
      label: "Ocean Sunrise",
    },
  ];

  return (
    <>
      <style>{`
        .gallery {
          padding: 100px 0;
          background: #f5f5dc;
        }

        .gallery__header {
          margin-bottom: 56px;
          text-align: center;
        }

        .section-title em {
          font-style: italic;
          color: goldenrod;
        }

        .gallery__grid {
          display: grid;
          grid-template-columns: repeat(3, 1fr);
          gap: 12px;
        }

        .gallery__item {
          position: relative;
          overflow: hidden;
          cursor: pointer;
          background: #eee;
        }

        .gallery__item--wide {
          grid-column: span 2;
        }

        .gallery__item img {
          width: 100%;
          height: 280px;
          object-fit: cover;
          transition: transform 0.5s ease;
        }

        .gallery__item--wide img {
          height: 320px;
        }

        .gallery__item:hover img {
          transform: scale(1.06);
        }

        .gallery__item-overlay {
          position: absolute;
          inset: 0;
          background: linear-gradient(to top, rgba(0,0,0,0.7), transparent);
          display: flex;
          justify-content: space-between;
          align-items: flex-end;
          padding: 20px;
          opacity: 0;
          transition: 0.3s;
        }

        .gallery__item:hover .gallery__item-overlay {
          opacity: 1;
        }

        .gallery__item-label {
          color: white;
        }

        .gallery__item-zoom {
          color: gold;
          font-size: 20px;
        }

        .lightbox {
          position: fixed;
          inset: 0;
          background: rgba(0,0,0,0.9);
          display: flex;
          flex-direction: column;
          justify-content: center;
          align-items: center;
        }

        .lightbox img {
          max-width: 90%;
          max-height: 80vh;
        }

        .lightbox__close {
          position: absolute;
          top: 20px;
          right: 30px;
          font-size: 24px;
          background: none;
          border: none;
          color: white;
          cursor: pointer;
        }

        @media (max-width: 768px) {
          .gallery__grid {
            grid-template-columns: 1fr 1fr;
          }
        }

        @media (max-width: 480px) {
          .gallery__grid {
            grid-template-columns: 1fr;
          }
        }
      `}</style>

      <section className="gallery">
        <div className="gallery__header">
          <h2 className="section-title">
            A Glimpse of <em>Paradise</em>
          </h2>
        </div>

        <div className="gallery__grid">
          {galleryItems.map((item, i) => (
            <div
              key={i}
              className={`gallery__item ${
                item.span === "wide" ? "gallery__item--wide" : ""
              }`}
              onClick={() => setLightbox(item)}
            >
              <img src={item.src} alt={item.label} />
              <div className="gallery__item-overlay">
                <span>{item.label}</span>
                <span>⊕</span>
              </div>
            </div>
          ))}
        </div>

        {lightbox && (
          <div className="lightbox" onClick={() => setLightbox(null)}>
            <button
              className="lightbox__close"
              onClick={() => setLightbox(null)}
            >
              ✕
            </button>
            <img
              src={lightbox.src}
              alt={lightbox.label}
              onClick={(e) => e.stopPropagation()}
            />
            <p style={{ color: "white" }}>{lightbox.label}</p>
          </div>
        )}
      </section>
    </>
  );
};

export default Gallery;
